 1	import * as React from 'react';
 2	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 3	import {
 4	  Card,
 5	  CardHeader,
 6	  CardBody,
 7	  Title,
 8	  TitleSizes,
 9	  ExpandableSection,
10	} from '@patternfly/react-core';
11	import './GettingStartedExpandableGrid.scss';
12	
13	type GettingStartedExpandableGridProps = {
14	  toggleContent?: React.ReactNode;
15	  title?: string;
16	  children?: React.ReactNode;
17	  isOpen: boolean;
18	  setIsOpen: (isOpen: boolean) => void;
19	  hideExpandable?: boolean;
20	};
21	
22	type ExpandableGridCardProps = {
23	  titleText?: string;
24	  children?: React.ReactNode;
25	  showHeader?: boolean;
26	};
27	
28	const CardTitle: React.FC<{ titleText: string }> = ({ titleText }) => {
29	  return (
30	    <Title
31	      headingLevel="h2"
32	      size={TitleSizes.lg}
33	      data-test="title"
34	      className="ocs-getting-started-expandable-section__toggle-text"
35	    >
36	      {titleText}
37	    </Title>
38	  );
39	};
40	
41	const ExpandableGridCard: React.FC<ExpandableGridCardProps> = ({
42	  titleText,
43	  children,
44	  showHeader,
45	}) => {
46	  return (
47	    <Card
48	      className="ocs-getting-started-expandable-grid"
49	      data-test="getting-started"
50	    >
51	      {!!showHeader && (
52	        <CardHeader>
53	          <CardTitle titleText={titleText} />
54	        </CardHeader>
55	      )}
56	      <CardBody>{children}</CardBody>
57	    </Card>
58	  );
59	};
60	
61	export const GettingStartedExpandableGrid: React.FC<
62	  GettingStartedExpandableGridProps
63	> = ({ toggleContent, title, children, isOpen, setIsOpen, hideExpandable }) => {
64	  const { t } = useCustomTranslation();
65	
66	  const titleText = title || t('Getting started resources');
67	  return !hideExpandable ? (
68	    <ExpandableSection
69	      onToggle={() => setIsOpen(!isOpen)}
70	      isExpanded={isOpen}
71	      displaySize="lg"
72	      className="ocs-getting-started-expandable-section"
73	      toggleContent={
74	        !toggleContent ? <CardTitle titleText={titleText} /> : toggleContent
75	      }
76	      data-test="getting-started-expandable"
77	    >
78	      <ExpandableGridCard>{children}</ExpandableGridCard>
79	    </ExpandableSection>
80	  ) : (
81	    <ExpandableGridCard titleText={titleText} showHeader>
82	      {children}
83	    </ExpandableGridCard>
84	  );
85	};

